package com.demo.web.dto.Events;

public class EventVoteActionRequest { private int userId; private String eventIdStr; private String groupIdStr; private String voteStr; public EventVoteActionRequest(int userId, String eventIdStr, String groupIdStr, String voteStr) { this.userId = userId; this.eventIdStr = eventIdStr; this.groupIdStr = groupIdStr; this.voteStr = voteStr; } public int getUserId() { return userId; } public void setUserId(int userId) { this.userId = userId; } public String getEventIdStr() { return eventIdStr; } public void setEventIdStr(String eventIdStr) { this.eventIdStr = eventIdStr; } public String getGroupIdStr() { return groupIdStr; } public void setGroupIdStr(String groupIdStr) { this.groupIdStr = groupIdStr; } public String getVoteStr() { return voteStr; } public void setVoteStr(String voteStr) { this.voteStr = voteStr; } }
